41	    if (this.cachePath && existsSync(this.cachePath)) {
42	      await rm(this.cachePath, { force: true, recursive: true })
43	      this.logger.log('[cache] cleared results cache at', this.cachePath)
44	    }
45	  }
46	
47	  async readFromCache(): Promise<void> {
48	    if (!this.cachePath) {
49	      return
50	    }
51	
52	    if (!fs.existsSync(this.cachePath)) {
53	      return
54	    }
55	
56	    const resultsCache = await fs.promises.readFile(this.cachePath, 'utf8')
57	    const { results, version } = JSON.parse(resultsCache || '[]')
58	    const [major, minor] = version.split('.')
59	    // handling changed in 0.30.0
60	    if (major > 0 || Number(minor) >= 30) {
61	      this.cache = new Map(results)
62	      this.version = version
63	      results.forEach(([spec]: [string]) => {
64	        const [projectName, relativePath] = spec.split(':')
65	        const keyMap = this.workspacesKeyMap.get(relativePath) || []
66	        keyMap.push(projectName)
67	        this.workspacesKeyMap.set(relativePath, keyMap)
68	      })
69	    }
70	  }
71	
72	  updateResults(files: File[]): void {
73	    files.forEach((file) => {
74	      const result = file.result
75	      if (!result) {
76	        return
77	      }
78	      const duration = result.duration || 0
79	      // store as relative, so cache would be the same in CI and locally
80	      const relativePath = relative(this.root, file.filepath)
81	      this.cache.set(`${file.projectName || ''}:${relativePath}`, {
82	        duration: duration >= 0 ? duration : 0,
83	        failed: result.state === 'fail',
84	      })
85	    })
86	  }
87	
88	  removeFromCache(filepath: string): void {
89	    this.cache.forEach((_, key) => {
90	      if (key.endsWith(filepath)) {
91	        this.cache.delete(key)
92	      }
93	    })
94	  }
95	
96	  async writeToCache(): Promise<void> {
97	    if (!this.cachePath) {
98	      return
99	    }
100	
101	    const results = Array.from(this.cache.entries())
102	
103	    const cacheDirname = dirname(this.cachePath)
104	
105	    if (!fs.existsSync(cacheDirname)) {
106	      await fs.promises.mkdir(cacheDirname, { recursive: true })
107	    }
108	
109	    const cache = JSON.stringify({
110	      version: this.version,
111	      results,
112	    })
113	
114	    await fs.promises.writeFile(this.cachePath, cache)
115	  }
116	}
