export interface DurationObservation {
  duration: number
  recordedAt: number
}

export function smoothDurations(observations: DurationObservation[], smoothing: DurationSmoothing): number {
  if (!observations.length) {
    return 0
  }

  switch (smoothing) {
    case 'average': {
      const sum = observations.reduce((acc, o) => acc + o.duration, 0)
      return Math.round(sum / observations.length)
    }
    case 'p95': {
      const sorted = [...observations].sort((a, b) => a.duration - b.duration)
      const index = Math.ceil(0.95 * sorted.length) - 1
      return sorted[index].duration
    }
    case 'median': {
      const sorted = [...observations].sort((a, b) => a.duration - b.duration)
      const n = sorted.length
      const mid = Math.floor(n / 2)
      if (n % 2 === 0) {
        return Math.floor((sorted[mid - 1].duration + sorted[mid].duration) / 2)
      }
      return sorted[mid].duration
    }
    case 'latest':
    default: {
      return observations.reduce((latest, o) => (o.recordedAt >= latest.recordedAt ? o : latest)).duration
    }
  }
}
