import fs from 'node:fs'
import { slash } from '@vitest/utils/helpers'
import { dirname, resolve } from 'pathe'

export interface DurationHistoryEntry {
  observations: DurationObservation[]
}

export type DurationHistory = Record<string, DurationHistoryEntry>

function resolveHistoryPath(root: string, durationHistoryPath: string): string {
  return resolve(root, durationHistoryPath)
}

function normalizeKey(key: string): string {
  return slash(key)
}

function extractObservations(entry: unknown): DurationObservation[] {
  if (entry == null) {
    return []
  }
  // legacy format: { "test/a.ts": 5000 }
  if (typeof entry === 'number') {
    return [{ duration: entry, recordedAt: 0 }]
  }
  if (typeof entry !== 'object') {
    return []
  }
  const value = entry as { observations?: unknown, duration?: unknown, recordedAt?: unknown }
  if (Array.isArray(value.observations)) {
    return value.observations.filter((o): o is DurationObservation =>
      !!o && typeof o === 'object' && typeof (o as any).duration === 'number' && typeof (o as any).recordedAt === 'number',
    )
  }
  if (typeof value.duration === 'number') {
    return [{
      duration: value.duration,
      recordedAt: typeof value.recordedAt === 'number' ? value.recordedAt : 0,
    }]
  }
  return []
}

export async function readDurationHistory(
  root: string,
  durationHistoryPath: string,
  ttl: number,
): Promise<DurationHistory | null> {
  const filepath = resolveHistoryPath(root, durationHistoryPath)

  if (!fs.existsSync(filepath)) {
    return null
  }

  let json: Record<string, unknown>
  try {
    const raw = await fs.promises.readFile(filepath, 'utf8')
    json = JSON.parse(raw)
  }
  catch {
    return null
  }

  if (!json || typeof json !== 'object') {
    return null
  }

  const now = Date.now()
  const history: DurationHistory = {}

  for (const key of Object.keys(json)) {
    let observations = extractObservations(json[key])

    if (ttl > 0) {
      observations = observations.filter(o => o.recordedAt === 0 || o.recordedAt >= now - ttl)
    }

    if (observations.length) {
      history[normalizeKey(key)] = { observations }
    }
  }

  return history
}

export async function recordFileDurations(
  root: string,
  durationHistoryPath: string,
  durationHistoryMaxRuns: number,
  durations: Map<string, number>,
  now: number,
): Promise<void> {
  if (!durations.size) {
    return
  }

  const filepath = resolveHistoryPath(root, durationHistoryPath)

  let existing: Record<string, unknown> = {}
  if (fs.existsSync(filepath)) {
    try {
      existing = JSON.parse(await fs.promises.readFile(filepath, 'utf8')) || {}
    }
    catch {
      existing = {}
    }
  }

  for (const [key, duration] of durations) {
    const normalizedKey = normalizeKey(key)
    const observations = extractObservations(existing[normalizedKey])
    observations.push({ duration: Math.round(duration), recordedAt: now })
    observations.sort((a, b) => b.recordedAt - a.recordedAt)
    const capped = observations.slice(0, durationHistoryMaxRuns)

    existing[normalizedKey] = durationHistoryMaxRuns === 1
      ? { duration: capped[0].duration, recordedAt: capped[0].recordedAt }
      : { observations: capped }
  }

  const dir = dirname(filepath)
  if (!fs.existsSync(dir)) {
    await fs.promises.mkdir(dir, { recursive: true })
  }

  await fs.promises.writeFile(filepath, JSON.stringify(existing))
}
