  file: T
  key: string
  duration: number
}

export interface ShardAssignment<T> {
  shards: T[][]
  loads: number[]
}

function compareByDurationDesc<T>(a: WeightedFile<T>, b: WeightedFile<T>): number {
  if (b.duration !== a.duration) {
    return b.duration - a.duration
  }
  return a.key < b.key ? -1 : a.key > b.key ? 1 : 0
}

export function binPackLPT<T>(
  weighted: WeightedFile<T>[],
  shardCount: number,
  shards: T[][] = Array.from({ length: shardCount }, () => []),
  loads: number[] = new Array(shardCount).fill(0),
): ShardAssignment<T> {
  const sorted = [...weighted].sort(compareByDurationDesc)

  for (const item of sorted) {
    let minIndex = 0
    for (let i = 1; i < shardCount; i++) {
      if (loads[i] < loads[minIndex]) {
        minIndex = i
      }
    }
    shards[minIndex].push(item.file)
    loads[minIndex] += item.duration
  }

  return { shards, loads }
}

export function roundRobinAssign<T>(weighted: WeightedFile<T>[], shardCount: number): ShardAssignment<T> {
  const shards: T[][] = Array.from({ length: shardCount }, () => [])
  const loads: number[] = new Array(shardCount).fill(0)
  const sorted = [...weighted].sort(compareByDurationDesc)

  let pointer = 0
  let direction = 1

  for (const item of sorted) {
    shards[pointer].push(item.file)
    loads[pointer] += item.duration

    pointer += direction
    if (pointer >= shardCount) {
      pointer = shardCount - 1
      direction = -1
    }
    else if (pointer < 0) {
      pointer = 0
      direction = 1
    }
  }

  return { shards, loads }
}

export function applyIsolateSlowThreshold<T>(
  weighted: WeightedFile<T>[],
  shardCount: number,
  threshold: number,
): ShardAssignment<T> {
  const slow = weighted.filter(w => w.duration > threshold).sort(compareByDurationDesc)
  const remaining = weighted.filter(w => !(w.duration > threshold))

  const shards: T[][] = Array.from({ length: shardCount }, () => [])
  const loads: number[] = new Array(shardCount).fill(0)

  if (slow.length >= shardCount) {
    for (let i = 0; i < shardCount - 1; i++) {
      shards[i].push(slow[i].file)
      loads[i] += slow[i].duration
    }
    const extras = slow.slice(shardCount - 1)
    const lastShard = shardCount - 1
    for (const w of extras) {
      shards[lastShard].push(w.file)
      loads[lastShard] += w.duration
    }
    for (const w of remaining) {
      shards[lastShard].push(w.file)
      loads[lastShard] += w.duration
    }
    return { shards, loads }
  }

  for (let i = 0; i < slow.length; i++) {
    shards[i].push(slow[i].file)
    loads[i] += slow[i].duration
  }

  return binPackLPT(remaining, shardCount, shards, loads)
}

export function checkRebalance(
  loads: number[],
  threshold: number,
  logger: { warn: (...args: any[]) => void },
): void {
  if (threshold <= 0 || !loads.length) {
    return
  }

  const maxLoad = Math.max(...loads)
  const minLoad = Math.min(...loads)

  if (maxLoad === 0) {
    return
  }

  const ratio = minLoad / maxLoad
  if (ratio < threshold) {
    logger.warn(`[vitest] Shard load is imbalanced: ratio=${ratio.toFixed(2)} threshold=${threshold.toFixed(2)}`)
  }
}
