    if (history === null) {
      const fallback = sequence.durationFallbackStrategy ?? 'hash'
      if (fallback === 'equal-split') {
        return this.equalSplitShard(files, index, count, config.root)
      }
      return this.hashShard(files, index, count, config.root)
    }

    const smoothing = sequence.durationSmoothing ?? 'latest'
    const weighted = this.weighFiles(files, config.root, history, smoothing)

    const isolateSlowThreshold = sequence.isolateSlowThreshold ?? 0

    const assignment = isolateSlowThreshold > 0
      ? applyIsolateSlowThreshold(weighted, count, isolateSlowThreshold)
