        : strategy === 'round-robin'
          ? roundRobinAssign(weighted, count)
          : binPackLPT(weighted, count)

    const rebalanceThreshold = sequence.rebalanceThreshold ?? 0
    checkRebalance(assignment.loads, rebalanceThreshold, this.ctx.logger)

