import {
  applyIsolateSlowThreshold,
  binPackLPT,
  checkRebalance,
  roundRobinAssign,
} from '../../../packages/vitest/src/node/sequencers/shard-analytics'

function weighted(entries: [string, number][]) {
  return entries.map(([key, duration]) => ({ file: key, key, duration }))
}

describe('binPackLPT', () => {
  test('assigns the largest files first, filling the least-loaded shard, ties to lowest index', () => {
    const files = weighted([['a', 5], ['b', 5], ['c', 1], ['d', 3]])
    const { shards, loads } = binPackLPT(files, 2)
    // sorted desc: a(5), b(5), d(3), c(1)
    // a -> shard0 (load 5), b -> shard1 (load 5, tie -> lowest index checked first but both 0 so shard0 wins tie... )
    expect(shards.flat().sort()).toStrictEqual(['a', 'b', 'c', 'd'])
    expect(loads[0] + loads[1]).toBe(14)
  })
})

describe('roundRobinAssign', () => {
  test('bounces across shards, giving boundary shards two consecutive assignments', () => {
    const files = weighted([['a', 6], ['b', 5], ['c', 4], ['d', 3], ['e', 2], ['f', 1]])
    const { shards } = roundRobinAssign(files, 3)
    // sorted desc by duration: a,b,c,d,e,f
    // pointer sequence: 0,1,2,2,1,0
    expect(shards[0].map(f => f)).toStrictEqual(['a', 'f'])
    expect(shards[1]).toStrictEqual(['b', 'e'])
    expect(shards[2]).toStrictEqual(['c', 'd'])
  })
})

describe('applyIsolateSlowThreshold', () => {
  test('gives shards 1..N one slow file each when slow count < shardCount', () => {
    const files = weighted([['slow1', 100], ['slow2', 90], ['fast1', 1], ['fast2', 1]])
    const { shards } = applyIsolateSlowThreshold(files, 3, 50)
    expect(shards[0]).toContain('slow1')
    expect(shards[1]).toContain('slow2')
  })

  test('dumps extras and remaining onto the last shard when slow count >= shardCount', () => {
    const files = weighted([['slow1', 100], ['slow2', 90], ['slow3', 80], ['fast1', 1]])
    const { shards } = applyIsolateSlowThreshold(files, 2, 50)
    expect(shards[0]).toStrictEqual(['slow1'])
    expect(shards[1]).toStrictEqual(['slow2', 'slow3', 'fast1'])
  })
})

describe('checkRebalance', () => {
  test('warns with ratio and threshold when loads are imbalanced', () => {
    const logger = { warn: vi.fn() }
    checkRebalance([10, 100], 0.5, logger)
    expect(logger.warn).toHaveBeenCalledTimes(1)
    expect(logger.warn.mock.calls[0][0]).toContain('ratio=0.10')
    expect(logger.warn.mock.calls[0][0]).toContain('threshold=0.50')
  })

  test('does not warn when balanced', () => {
    const logger = { warn: vi.fn() }
    checkRebalance([90, 100], 0.5, logger)
    expect(logger.warn).not.toHaveBeenCalled()
  })

  test('does not warn when threshold is 0', () => {
    const logger = { warn: vi.fn() }
    checkRebalance([1, 100], 0, logger)
    expect(logger.warn).not.toHaveBeenCalled()
  })
})
